algorithm:
Modified greedy insertion with regret-based candidate selection and fallback to seed creation: evaluate all feasible insertions across existing non-empty assigns plus one new empty assign, compute insertion cost delta and regret value, pick best regret-weighted insertion, create new assign if none feasible.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type Candidate struct {
		assignIdx int
		costDelta float64
		feasible  bool
	}
	newOrderCount := len(oris)
	if newOrderCount == 0 || len(dess) != newOrderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	activeLimit := dispatch.AssignsLen
	for i := 0; i < activeLimit; i++ {
		if dispatch.Assigns[i].StationsLen == 0 {
			activeLimit--
			if i < activeLimit {
				dispatch.Assigns[i], dispatch.Assigns[activeLimit] = dispatch.Assigns[activeLimit], dispatch.Assigns[i]
				i--
			}
		}
	}
	shuffleActive := make([]int, activeLimit)
	for i := range shuffleActive {
		shuffleActive[i] = i
	}
	for i := range shuffleActive {
		j := i + rand.Intn(activeLimit-i)
		shuffleActive[i], shuffleActive[j] = shuffleActive[j], shuffleActive[i]
	}
	orderPermutation := make([]int, newOrderCount)
	for i := range orderPermutation {
		orderPermutation[i] = i
	}
	for i := range orderPermutation {
		j := i + rand.Intn(newOrderCount-i)
		orderPermutation[i], orderPermutation[j] = orderPermutation[j], orderPermutation[i]
	}
	for _, permIdx := range orderPermutation {
		ori := oris[permIdx]
		des := dess[permIdx]
		shipID := total_ship + permIdx
		bestCandidates := make([]Candidate, 0, activeLimit+1)
		for _, ai := range shuffleActive {
			originalCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				if dispatch.Assigns[ai].Cost >= 0 {
					delta := dispatch.Assigns[ai].Cost - originalCost
					bestCandidates = append(bestCandidates, Candidate{assignIdx: ai, costDelta: delta, feasible: true})
				} else {
					dispatch.Assigns[ai].RemoveShip(shipID)
					dispatch.Assigns[ai].GenRoute()
				}
			}
		}
		if activeLimit < MAXASSIGNS {
			emptyIdx := activeLimit
			if activeLimit < dispatch.AssignsLen {
				emptyIdx = dispatch.AssignsLen
